void *plus(void *agr){
	param* agrs = (param*)agr;
	agrs->c = agrs->b + agrs->a;
	printf("the test result is %d\n",agrs->c);
}

int main(){
		void* thread_result;
        pthread_attr_t attrp;
        pthread_attr_init(&attrp);
        pthread_attr_setstacksize(&attrp, THREAD_STACK_DEPTH);

        for( i=0; i<10; i++) {
			param *useagrs = malloc(sizeof(param));
            useagrs->a = i;
            useagrs->b = i+1;    
            pthread_create(&thread_ids[i], &attrp, plus, (void*)useagrs);
			pthread_join(thread_ids[i], &thread_result);
			printf("thread result is %d\n",(int*)thread_result);
		}
